// Build a lookup map from scraped data by numeric id
const scrapedById: Record<number, any> = {};
(rawConservatoriums as any[]).forEach((c: any) => { scrapedById[c.id] = c; });

// Build a lookup map from enriched CSV i18n data by numeric id
const enrichedById: Record<string, (typeof enrichedData)[number]> = {};
(enrichedData as (typeof enrichedData)).forEach((e) => { enrichedById[e.id] = e; });

// The scraper's numbering differs from constadmin.json in some cases:
// - constadmin id=84 is ICM (הקונסרבטוריון הישראלי למוסיקה, תל אביב), email canellis@icm.org.il
// - conservatoriums.json id=82 is also ICM (same institution, different scraper id)
// - constadmin id=82 is שער הנגב — which has NO entry in conservatoriums.json
// Fix: copy ICM scraped data to key 84, and clear key 82 so שער הנגב gets empty scraped data.
scrapedById[84] = scrapedById[82]; // give ICM its real scraped data
delete scrapedById[82];            // שער הנגב has no scraped data

// Stable slug IDs for specific conservatoriums (overrides the default `cons-${admin.id}`)
const conservatoriumIdOverride: Record<number, string> = {
    84: 'israel-conservatory-of-music-tel-aviv-icm__cons-82',
};

// Generate Conservatoriums from the JSON file, enriched with scraped profile data
export const conservatoriums: Conservatorium[] = constAdminData.map((admin, index) => {
    const isHodHasharon = admin.location === 'הוד השרון';
    const scraped: any = scrapedById[admin.id] || {};
    const enriched = enrichedById[String(admin.id)];

    // Map scraped departments
    const departments = scraped.departments?.map((d: any) => ({
        name: d.name,
        headTeacher: d.head,
        link: d.link,
        photoUrl: d.photo,
    }));

    // Map scraped teachers
    const teachers = scraped.teachers?.map((t: any, i: number) => ({
        id: `teacher-dir-${admin.id}-${i}`,
        name: t.name,
        role: t.role,
        photoUrl: t.photo_url,
    }));

    // Map scraped branches
    const branchesInfo = scraped.branches?.map((b: any) => ({
        name: b.name,
        address: b.address,
        tel: b.tel,
        email: b.email,
        manager: b.manager,
    }));

    // Map location
    const location = scraped.location ? {
        city: scraped.location.city || scraped.city || admin.location,
        cityEn: scraped.city_en || enriched?.cityEn,
        cityI18n: enriched ? { he: enriched.cityHe, en: enriched.cityEn, ar: enriched.cityAr, ru: enriched.cityRu } : undefined,
        address: scraped.location.address || enriched?.addressHe,
        addressI18n: enriched ? { he: enriched.addressHe, en: enriched.addressEn, ar: enriched.addressAr, ru: enriched.addressRu } : undefined,
        coordinates: scraped.location.coordinates,
        googleMapsUrl: enriched?.mapsUrl || undefined,
        branches: scraped.location.branches,
    } : {
        city: admin.location,
        cityI18n: enriched ? { he: enriched.cityHe, en: enriched.cityEn, ar: enriched.cityAr, ru: enriched.cityRu } : undefined,
        addressI18n: enriched ? { he: enriched.addressHe, en: enriched.addressEn, ar: enriched.addressAr, ru: enriched.addressRu } : undefined,
        googleMapsUrl: enriched?.mapsUrl || undefined,
    };

    // Map manager from scraped (richer) or admin data
    const manager = scraped.manager ? {
        name: scraped.manager.name || admin.manager_name,
        role: scraped.manager.role,
        bio: scraped.manager.bio,
        photoUrl: scraped.manager.photo_url,
    } : {
        name: admin.manager_name,
    };

    // Pre-built translations for cons-15 (Hod HaSharon) so the profile editor shows AR/RU without requiring a live AI call
    const hodHasharonTranslations = isHodHasharon ? {
        en: {
            name: 'Hod HaSharon Music Conservatory',
            about: scraped.about ? 'The Hod HaSharon Music Conservatory offers a broad range of musical education programs for children and adults, providing high-quality instrumental and vocal training in a supportive and inspiring environment.' : undefined,
            openingHours: scraped.opening_hours || undefined,
            manager: scraped.manager ? { role: 'Director', bio: 'Director and artistic leader of the conservatory.' } : undefined,
        },
        ar: {
            name: 'كونسرفتوار هود هشارون للموسيقى',
            about: scraped.about ? 'يقدم كونسرفتوار هود هشارون للموسيقى مجموعة واسعة من برامج التعليم الموسيقي للأطفال والبالغين، مع توفير تدريب متميز على العزف والغناء في بيئة داعمة وملهمة.' : undefined,
            openingHours: scraped.opening_hours || undefined,
            manager: scraped.manager ? { role: 'مدير', bio: 'مدير وقائد فني للكونسرفتوار.' } : undefined,
        },
        ru: {
            name: 'Музыкальная консерватория Ход ха-Шарон',
            about: scraped.about ? 'Музыкальная консерватория Ход ха-Шарон предлагает широкий спектр программ музыкального образования для детей и взрослых, обеспечивая высококачественное инструментальное и вокальное обучение в поддерживающей и вдохновляющей среде.' : undefined,
            openingHours: scraped.opening_hours || undefined,
            manager: scraped.manager ? { role: 'Директор', bio: 'Директор и художественный руководитель консерватории.' } : undefined,
        },
    } : undefined;

    return {
        id: conservatoriumIdOverride[admin.id] ?? `cons-${admin.id}`,
        name: scraped.name || (admin.organization ? `${admin.location} (${admin.organization})` : admin.location),
        nameEn: scraped.name_en || enriched?.cityEn,
        nameI18n: enriched ? { he: enriched.cityHe, en: enriched.cityEn, ar: enriched.cityAr, ru: enriched.cityRu } : undefined,
        translations: hodHasharonTranslations,
        translationMeta: hodHasharonTranslations ? {
            lastTranslatedAt: '2025-01-01T00:00:00.000Z',
            sourceHash: '',
            translatedBy: 'AI' as const,
            aiModel: 'mock-seed',
        } : undefined,
        tier: tierCycle[index % 3],
        stampUrl: `https://picsum.photos/seed/stamp${admin.id}/200/200`,
        newFeaturesEnabled: isHodHasharon,
        aiAgentsConfig: isHodHasharon ? {
            "matchmaker-agent": true,
            "composition-suggester": true,
            "reschedule-agent": false,
            "progress-report-agent": false,
            "admin-alerts-agent": false,
            "lead-nurture-agent": false,
        } : undefined,
        // --- Enriched i18n fields from CSV ---
        managerNameI18n: enriched ? { he: enriched.adminHe, en: enriched.adminEn, ar: enriched.adminAr, ru: enriched.adminRu } : undefined,
        organizationI18n: enriched ? { he: enriched.orgHe, en: enriched.orgEn, ar: enriched.orgAr, ru: enriched.orgRu } : undefined,
        website: enriched?.website !== 'N/A' ? enriched?.website : undefined,
        logoUrl: enriched?.logoUrl || undefined,
        imageUrl: enriched?.imageUrl || undefined,
        mapsUrl: enriched?.mapsUrl || undefined,
        mobile: enriched?.mobile || undefined,
        // Public profile
        about: scraped.about,
        email: scraped.email?.split(';')[0].trim() || enriched?.email || 'no-email@example.com',
        secondaryEmail: scraped.secondary_email,
        tel: scraped.tel || admin.office_phone || enriched?.phone,
        // Prefer authoritative CSV website. If CSV explicitly says N/A, do NOT fall back to scraped
        // (scraper has cross-contamination errors assigning same URL to multiple conservatoriums)
        officialSite: enriched?.website && enriched.website !== 'N/A' ? enriched.website : undefined,
        openingHours: scraped.opening_hours,
        location,
        manager,
        pedagogicalCoordinator: scraped.pedagogical_coordinator ? {
            name: scraped.pedagogical_coordinator.name,
            role: scraped.pedagogical_coordinator.role,
            bio: scraped.pedagogical_coordinator.bio,
            photoUrl: scraped.pedagogical_coordinator.photo_url,
        } : undefined,
        leadingTeam: scraped.leading_team ? scraped.leading_team.map((m: any) => ({
            name: m.name,
            role: m.role,
            bio: m.bio,
            photoUrl: m.photo_url,
        })) : (admin.id === 15 ? [
            {
                name: "מיכאל גורביץ'",
                role: "מנהל אמנותי",
                bio: "בימאי ומחזאי, חתן פרס ישראל",
                photoUrl: "https://alumahod.com/wp-content/uploads/2025/11/%D7%9E%D7%99%D7%9B%D7%90%D7%9C-%D7%92%D7%95%D7%A8%D7%91%D7%99%D7%A5.jpg"
            }
        ] : undefined),
        departments,
        branchesInfo,
        teachers,
        programs: scraped.programs,
        ensembles: scraped.ensembles,
        socialMedia: scraped.social_media ? {
            facebook: scraped.social_media.facebook,
            instagram: scraped.social_media.instagram,
            youtube: scraped.social_media.youtube,
            tiktok: scraped.social_media.tiktok,
            whatsapp: scraped.social_media.whatsapp,
        } : undefined,
        photoUrls: scraped.photos?.length > 0 ? scraped.photos : [UNSPLASH_CONSERVATORIUM_PHOTOS[admin.id % 10]],
    };
});


